from flask import Flask, request, jsonify
from functools import wraps

app = Flask(__name__)

# Mock data
users = {
    1: {"email": "user1@example.com", "username": "user1", "role": "user", "account_status": "active", "subscription_tier": "free"},
    2: {"email": "user2@example.com", "username": "user2", "role": "moderator", "account_status": "active", "subscription_tier": "pro"},
}

current_user = {"id": 99, "role": "admin"}

def admin_required(f):
    @wraps(f)
    def decorated_function(*args, **kwargs):
        if current_user['role'] != 'admin':
            return jsonify({"error": "Admin access required"}), 403
        return f(*args, **kwargs)
    return decorated_function

@app.route('/api/users/<int:user_id>', methods=['PUT'])
@admin_required
def update_user(user_id):
    if user_id not in users:
        return jsonify({"error": "User not found"}), 404

    data = request.json
    allowed_fields = {"email", "username", "role", "account_status", "subscription_tier"}
    for key in data:
        if key in allowed_fields:
            users[user_id][key] = data[key]

    return jsonify(users[user_id]), 200

